def enable_ui_elements():
    df_columns = list(table_dis.model.df)
    c_cmb_list = [cmb_type_column, entry_dup_column1, entry_dup_column2, entry_dup_column3, entry_null_column, cmb_query_column]
    for cmb in c_cmb_list:
        cmb.config(state="readonly", values=df_columns)

    c_b_list = [b_locate, b_cut, b_query, b_turn_data, b_set_index, b_reserve, b_dup_delete, b_dup_show, b_slice,
                b_null_show, b_null_delete, b_null_fill, b_astype, b_update_info, b_total_show, b_replace, b_save_path]
    for b in c_b_list:
        b.config(state="normal", cursor="hand2")

    b_cover_data.config(state="normal", cursor="hand2", text="保存修改")
    toolbar_cb.config(state="normal")

