def confirm_path():
    global df0
    try:
        if str(df0_entry.get())[-1] == "v":
            df0 = pd.read_csv(df0_entry.get(), engine='c')  # 使用C引擎加速
        elif str(df0_entry.get())[-1] == "x":
            df0 = pd.read_excel(df0_entry.get(), engine='openpyxl')

        # 限制初始显示行数提高性能
        if df0.shape[0] >= 50000:
            table_dis.model.df = df0.head(50000)
            table_dis.show()
            thread_ui()
            tk.messagebox.showinfo("Info", '该文件数据较大，当前仅显示50000行数据，若需要显示完整数据，请点击 “显示完整数据”。')

        else:
            table_dis.model.df = df0
            table_dis.show()
            thread_ui()

        confirm_button.config(text="重新载入")
        enable_ui_elements()  # 抽取按钮启用逻辑

    except Exception as e:
        tk.messagebox.showerror("Error", f"文件加载失败: {str(e)}")

