def select_import_module():
    global df_import
    if import_data_var.get() == '0':
        df_import = table_dis.model.df
    elif import_data_var.get() == '1':
        df_import = i_m_table_dis.model.df
    elif import_data_var.get() == '2':
        df_import = i_s_table_dis.model.df
    elif import_data_var.get() == '3':
        df_import = v_table_dis.model.df
    return df_import

def import_data():
    import_window = ttk.Toplevel()
    import_window.title("Import Data")
    import_window.geometry("240x145")
    import_window.grab_set()
    import_window.place_window_center()

    ttk.Radiobutton(import_window, text="数据整合(主表格)", variable=import_data_var, value=1).grid(row=1, column=0, columnspan=2, padx=45, pady=5)
    ttk.Radiobutton(import_window, text="数据整合(次表格)", variable=import_data_var, value=2).grid(row=2, column=0, columnspan=2, padx=45, pady=5)
    ttk.Radiobutton(import_window, text="数据可视化", variable=import_data_var, value=3).grid(row=3, column=0, columnspan=2, padx=45, pady=5)
    import_data_var.set('1')

    def import_data_show():
        global df0
        try:
            df0 = select_import_module()
            if df0.shape[0] >= 50000:
                table_dis.model.df = df0.head(50000)
                table_dis.show()
                thread_ui()
                tk.messagebox.showinfo("Info", '该文件数据较大，当前仅显示50000行数据，若需要显示完整数据，请点击 “显示完整数据”。')
            else:
                table_dis.model.df = df0
                table_dis.show()
                thread_ui()
            enable_ui_elements() # 抽取按钮启用逻辑
            tk.messagebox.showinfo("Info", '导入成功！')
            import_window.destroy()
        except Exception as e:
            tk.messagebox.showerror("Error", f"模块导入失败: {str(e)}")

    ttk.Button(import_window, text='确定', cursor='hand2', command=import_data_show).grid(row=4, column=0, pady=10, padx=15)
    ttk.Button(import_window, text='取消', cursor='hand2', command=import_window.destroy).grid(row=4, column=1, pady=10)

    import_window.wait_window()

