def query():
    try:
        if cmb_query_column.get() != "" and cmb_query_condition.get() != "" and entry_query_value.get() != "":
            # 获取列的数据类型
            column_type = df0[cmb_query_column.get()].dtype
            value = entry_query_value.get()
            # 根据条件进行筛选
            if cmb_query_condition.get() == ">":
                if np.issubdtype(column_type, np.number):  # 如果是数值类型
                    value = float(value)  # 转换为数值
                table_dis.model.df = df0[df0[cmb_query_column.get()] > value]
            elif cmb_query_condition.get() == "<":
                if np.issubdtype(column_type, np.number):  # 如果是数值类型
                    value = float(value)  # 转换为数值
                table_dis.model.df = df0[df0[cmb_query_column.get()] < value]
            elif cmb_query_condition.get() == "<=":
                if np.issubdtype(column_type, np.number):  # 如果是数值类型
                    value = float(value)  # 转换为数值
                table_dis.model.df = df0[df0[cmb_query_column.get()] <= value]
            elif cmb_query_condition.get() == ">=":
                if np.issubdtype(column_type, np.number):  # 如果是数值类型
                    value = float(value)  # 转换为数值
                table_dis.model.df = df0[df0[cmb_query_column.get()] >= value]
            elif cmb_query_condition.get() == "=":
                if np.issubdtype(column_type, np.number):  # 如果是数值类型
                    value = float(value)  # 转换为数值
                table_dis.model.df = df0[df0[cmb_query_column.get()] == value]
            elif cmb_query_condition.get() == "≠":
                if np.issubdtype(column_type, np.number):  # 如果是数值类型
                    value = float(value)  # 转换为数值
                table_dis.model.df = df0[df0[cmb_query_column.get()] != value]
            elif cmb_query_condition.get() == "首位字符为":
                table_dis.model.df = df0[df0[cmb_query_column.get()].str[0] == value]
            elif cmb_query_condition.get() == "末位字符为":
                table_dis.model.df = df0[df0[cmb_query_column.get()].str[-1] == value]
            elif cmb_query_condition.get() == "字符串长度为":
                value = float(value)
                table_dis.model.df = df0[df0[cmb_query_column.get()].str.len() == value]
            elif cmb_query_condition.get() == "首位字符不为":
                table_dis.model.df = df0[df0[cmb_query_column.get()].str[0] != value]
            elif cmb_query_condition.get() == "末位字符不为":
                table_dis.model.df = df0[df0[cmb_query_column.get()].str[-1] != value]
            elif cmb_query_condition.get() == "字符串长度不为":
                value = float(value)
                table_dis.model.df = df0[df0[cmb_query_column.get()].str.len() != value]
            elif cmb_query_condition.get() == "包含":
                table_dis.model.df = df0[df0[cmb_query_column.get()].str.contains(value, na=False)]
            elif cmb_query_condition.get() == "不包含":
                table_dis.model.df = df0[~df0[cmb_query_column.get()].str.contains(value, na=False)]

            table_dis.show()
            update_info()
            b_cover_data.config(text="保存修改")
        else:
            tk.messagebox.showinfo(message="请输入并完善筛选条件！", title="Info")
    except ValueError:
        tk.messagebox.showerror("Error", "输入值格式错误，请检查输入值是否与列的数据类型匹配！")
    except Exception as e:
        tk.messagebox.showerror("Error", f"筛选出错: {str(e)}")

def change_type():
    global c_info_var
    global df0
    try:
        if type_box.get() == "字符串str":
            table_dis.model.df[cmb_type_column.get()] = df0[cmb_type_column.get()].astype(str)
        elif type_box.get() == "整数int":
            table_dis.model.df[cmb_type_column.get()] = df0[cmb_type_column.get()].replace(',', '', regex=True).fillna(0).astype(int).replace({0: np.nan})
        elif type_box.get() == "浮点数float":
            table_dis.model.df[cmb_type_column.get()] = df0[cmb_type_column.get()].replace(',', '', regex=True).fillna(0).astype(float).replace({0: np.nan})
        elif type_box.get() == "布尔值bool":
            table_dis.model.df[cmb_type_column.get()] = df0[cmb_type_column.get()].astype(bool)
        elif type_box.get() == "浮点数（由百分数转换）":
            table_dis.model.df[cmb_type_column.get()] = df0[cmb_type_column.get()].str.strip('%').astype(float)/100
        elif type_box.get() == "百分数object":
            table_dis.model.df[cmb_type_column.get()] = df0[cmb_type_column.get()].replace(',', '', regex=True).fillna(0).apply(lambda x: format(x, '.2%')).astype(str).replace({'0.00%': np.nan})
        elif type_box.get() == "日期date（年）":
            table_dis.model.df[cmb_type_column.get()] = pd.to_datetime(df0[cmb_type_column.get()], format='%Y')
        elif type_box.get() == "日期date（年月）":
            table_dis.model.df[cmb_type_column.get()] = pd.to_datetime(df0[cmb_type_column.get()], format='%Y-%m')
        elif type_box.get() == "日期date（年月日）":
            table_dis.model.df[cmb_type_column.get()] = pd.to_datetime(df0[cmb_type_column.get()], format='%Y-%m-%d')
        elif type_box.get() == "列表":
            table_dis.model.df[cmb_type_column.get()] = df0[cmb_type_column.get()].apply(lambda s: eval(s))
        tk.messagebox.showinfo(message="设置成功！", title="Info")
        update_info()
        table_dis.show()
        b_cover_data.config(text="保存修改")
    except pd.errors.IntCastingNaNError:
        tk.messagebox.showerror(message="存在缺失值或非有限值，转换失败！", title="Error")
    except TypeError as e:
        if type_box.get() == "列表":
            tk.messagebox.showinfo(message="列表不可哈希，请进一步处理！", title="Info")
        else:
            tk.messagebox.showerror("Error", f"转换出错: {str(e)}")
    except Exception as e:
        tk.messagebox.showerror("Error", f"转换出错: {str(e)}")

def slice_value():
    slice_window = ttk.Toplevel()
    slice_window.title("Slice")
    slice_window.geometry("260x140")
    slice_window.grab_set()
    slice_window.place_window_center()
    df_columns = list(table_dis.model.df)
    slice_column_frame = ttk.Frame(slice_window)
    slice_column_frame.grid(row=0, column=0, columnspan=4)
    ttk.Label(slice_column_frame, text="请选择列：", font=("微软雅黑", 10)).grid(row=0, column=0, padx=(25,1), pady=2)
    cmb_slice_column = ttk.Combobox(slice_column_frame, font=("微软雅黑", 8), width=12, values=df_columns, state="readonly")
    cmb_slice_column.grid(row=0, column=1, padx=(0, 0), pady=2)
    cmb_slice_option1 = ttk.Combobox(slice_window, font=("微软雅黑", 8), width=4, values=('保留', '去除'), state="readonly")
    cmb_slice_option1.grid(row=1, column=0, padx=(25, 0), pady=2)
    cmb_slice_option2 = ttk.Combobox(slice_window, font=("微软雅黑", 8), width=3, values=('前', '后'), state="readonly")
    cmb_slice_option2.grid(row=1, column=1, padx=1, pady=2)
    slice_wei_spinbox = ttk.Spinbox(slice_window, from_=0, to=10, width=2)
    slice_wei_spinbox.grid(row=1, column=2, padx=1, pady=2)
    ttk.Label(slice_window, text="位", font=("微软雅黑", 10)).grid(row=1, column=3, padx=1, pady=2)


    def slice_value_2():
        try:
            if cmb_slice_column.get() != "":
                column_type = table_dis.model.df[cmb_slice_column.get()].dtype
                if np.issubdtype(column_type, object):
                    if cmb_slice_option1.get() == "保留" and cmb_slice_option2.get() == "前" and slice_wei_spinbox.get() != "":
                        wei = int(slice_wei_spinbox.get())
                        table_dis.model.df[cmb_slice_column.get()] = df0[cmb_slice_column.get()].str.slice(0, wei)
                        tk.messagebox.showinfo("Info", message='切片成功！')
                        table_dis.show()
                    elif cmb_slice_option1.get() == "保留" and cmb_slice_option2.get() == "后" and slice_wei_spinbox.get() != "":
                        wei = -int(slice_wei_spinbox.get())
                        table_dis.model.df[cmb_slice_column.get()] = df0[cmb_slice_column.get()].str.slice(wei, )
                        tk.messagebox.showinfo("Info", message='切片成功！')
                        table_dis.show()
                    elif cmb_slice_option1.get() == "去除" and cmb_slice_option2.get() == "前" and slice_wei_spinbox.get() != "":
                        wei = int(slice_wei_spinbox.get())
                        table_dis.model.df[cmb_slice_column.get()] = df0[cmb_slice_column.get()].str.slice(wei, )
                        tk.messagebox.showinfo("Info", message='切片成功！')
                        table_dis.show()
                    elif cmb_slice_option1.get() == "去除" and cmb_slice_option2.get() == "后" and slice_wei_spinbox.get() != "":
                        wei = int(slice_wei_spinbox.get())
                        table_dis.model.df[cmb_slice_column.get()] = df0[cmb_slice_column.get()].str.slice(0,-wei)
                        tk.messagebox.showinfo("Info", message='切片成功！')
                        table_dis.show()
                else:
                    tk.messagebox.showerror("Error", message='切片失败，请先将数值类型转化为字符串！')
            elif cmb_slice_column.get() == "":
                tk.messagebox.showerror("Error", message='请选择列！')
            else:
                tk.messagebox.showerror("Error", message='信息不足，无法进行数值切片！')

        except Exception as e:
            tk.messagebox.showerror("Error", f"替换出错: {str(e)}")

