def replace_value():
    replace_window = ttk.Toplevel()
    replace_window.title("Replace")
    replace_window.geometry("260x165")
    replace_window.grab_set()
    replace_window.place_window_center()
    df_columns = list(table_dis.model.df)
    ttk.Label(replace_window, text="请选择列：", font=("微软雅黑", 10)).grid(row=0, column=0, padx=(10,1), pady=2)
    cmb_replace_column = ttk.Combobox(replace_window, font=("微软雅黑", 8), width=13, values=df_columns, state="readonly")
    cmb_replace_column.grid(row=0, column=1, padx=1, pady=2)
    ttk.Label(replace_window, text="被替换值：", font=("微软雅黑", 10)).grid(row=1, column=0, padx=(10,1), pady=2)
    e_replace_value = ttk.Entry(replace_window, font=("微软雅黑", 10), width=12)
    e_replace_value.grid(row=1, column=1, padx=1, pady=2)
    ttk.Label(replace_window, text="替换值：", font=("微软雅黑", 10)).grid(row=2, column=0, padx=(10,1), pady=2)
    e_new_value = ttk.Entry(replace_window, font=("微软雅黑", 10), width=12)
    e_new_value.grid(row=2, column=1, padx=1, pady=2)

    def replace_value_2():
        try:
            value_list = table_dis.model.df[cmb_replace_column.get()].unique().tolist()
            if cmb_replace_column.get() != "" and e_replace_value.get() in value_list and e_new_value.get() !="":
                column_type = df0[cmb_replace_column.get()].dtype
                value = e_new_value.get()
                if np.issubdtype(column_type, np.number):  # 如果是数值类型
                    value = float(value)  # 转换为数值

                table_dis.model.df[cmb_replace_column.get()] = df0[cmb_replace_column.get()].replace({e_replace_value.get() :value})
                tk.messagebox.showinfo(message="替换成功！", title="Info")
                table_dis.show()
                b_cover_data.config(text="保存修改")
            elif cmb_replace_column.get() == "":
                tk.messagebox.showinfo(message="请选择列！", title="Info")
            elif e_replace_value.get() not in value_list:
                tk.messagebox.showinfo(message="选择的列中不包含被替换值，请检查后重新输入！", title="Info")
            elif e_new_value.get() == "":
                tk.messagebox.showinfo(message="请输入替换值！", title="Info")
        except Exception as e:
            tk.messagebox.showerror("Error", f"替换出错: {str(e)}")

    ttk.Button(replace_window, text="确定", style="outline", command=replace_value_2).grid(row=3, column=0, padx=(55, 0), pady=4)
    ttk.Button(replace_window, text="取消", style="outline", command=replace_window.destroy).grid(row=3, column=1, padx=0, pady=4)
    replace_window.wait_window()

