def fill_null():
    if entry_null_column.get() == "":
        tk.messagebox.showinfo(message="请先选择要填充的列！", title="Info")
    else:
        fill_null_window = ttk.Toplevel()
        fill_null_window.title("Fill Null")
        fill_null_window.geometry("320x100")
        fill_null_window.place_window_center()
        fill_null_window.grab_set()
        fn_choose_frame = ttk.Frame(fill_null_window)
        fn_choose_frame.pack(side=TOP, fill=X)
        ttk.Label(fn_choose_frame, text="请选择填充值：", font=("微软雅黑", 10)).pack(side="left", padx=(20, 1), pady=10)
        fill_null_cb = ttk.Combobox(fn_choose_frame, font=("微软雅黑", 8), width=16, values=("平均值mean", "众数mode", "中位数median", "0", "自定义"), state="readonly")
        fill_null_cb.pack(side="left")

        fn_bframe = ttk.Frame(fill_null_window)
        fn_bframe.pack(side=TOP, fill=X)

        def fill_null_2():
            if fill_null_cb.get() == "平均值mean":
                fill_content = df0[entry_null_column.get()].mean()
                table_dis.model.df = df0.fillna({entry_null_column.get(): fill_content})
                thread_ui()
                tk.messagebox.showinfo(message="填充成功！", title="Info")
                fill_null_window.destroy()
                b_cover_data.config(text="保存修改")
            elif fill_null_cb.get() == "众数mode":
                fill_content = statistics.mode(df0[entry_null_column.get()])
                table_dis.model.df = df0.fillna({entry_null_column.get(): fill_content})
                thread_ui()
                tk.messagebox.showinfo(message="填充成功！", title="Info")
                fill_null_window.destroy()
                b_cover_data.config(text="保存修改")
            elif fill_null_cb.get() == "中位数median":
                fill_content = df0[entry_null_column.get()].median()
                table_dis.model.df = df0.fillna({entry_null_column.get(): fill_content})
                thread_ui()
                tk.messagebox.showinfo(message="填充成功！", title="Info")
                fill_null_window.destroy()
                b_cover_data.config(text="保存修改")
            elif fill_null_cb.get() == "0":
                fill_content = 0
                table_dis.model.df = df0.fillna({entry_null_column.get(): fill_content})
                thread_ui()
                tk.messagebox.showinfo(message="填充成功！", title="Info")
                fill_null_window.destroy()
                b_cover_data.config(text="保存修改")
            else:
                fill_null_window_custom = ttk.Toplevel()
                fill_null_window_custom.title("Fill Null Custom")
                fill_null_window_custom.geometry("200x160")
                fill_null_window_custom.grab_set()
                fill_null_window_custom.place_window_center()
                fill_null_custom_lbframe = ttk.Frame(fill_null_window_custom)
                fill_null_custom_lbframe.pack(side="top", fill=X)
                ttk.Label(fill_null_custom_lbframe, text="请输入填充值：", font=("微软雅黑", 10)).pack(side="left")
                fill_null_custom_entry_frame = ttk.Frame(fill_null_window_custom)
                fill_null_custom_entry_frame.pack(side="top", fill=X)
                fill_null_custom_entry = ttk.Entry(fill_null_custom_entry_frame, width=18, font=("微软雅黑", 10))
                fill_null_custom_entry.pack(side="left", padx=8)

                def custom():
                    fill_content = fill_null_custom_entry.get()
                    fill_null_window_custom.destroy()
                    fill_null_window.destroy()
                    table_dis.model.df = df0.fillna({entry_null_column.get(): fill_content})
                    thread_ui()
                    tk.messagebox.showinfo(message="填充成功！", title="Info")
                    b_cover_data.config(text="保存修改")

                fill_null_custom_b_frame = ttk.Frame(fill_null_window_custom)
                fill_null_custom_b_frame.pack(side="top", fill=X)
                ttk.Button(fill_null_custom_b_frame, text="确定", style="outline", command=custom).pack(side="top", padx=30, pady=(15,1))
                ttk.Button(fill_null_custom_b_frame, text="取消", style="outline", command=fill_null_window_custom.destroy).pack(side="top", padx=30, pady=8)


        ttk.Button(fn_bframe, text="填充", style="outline", command=fill_null_2).pack(side="left", padx=(92, 40), pady=10)
        ttk.Button(fn_bframe, text="取消", style="outline", command=fill_null_window.destroy).pack(side="left", padx=0, pady=10)

