# 定义integrate模块函数
def i_split_and_cat():
    sac_window = ttk.Toplevel()
    sac_window.title("Explode")
    sac_window.geometry("300x260")
    sac_window.grab_set()
    sac_window.place_window_center()
    sac_tab = ttk.Frame(sac_window)
    sac_tab.pack(pady=2, fill=X, side=TOP)
    sac_nb = ttk.Notebook(sac_tab)
    sac_nb.pack(side=LEFT, padx=5, expand=YES, fill=BOTH)
    split_frame = ttk.Frame(sac_nb)
    explode_frame = ttk.Frame(sac_nb)
    cat_frame = ttk.Frame(sac_nb)
    sac_nb.add(child=split_frame, text="拆分列为列", sticky=NW)
    sac_nb.add(child=explode_frame, text="拆分列为行", sticky=NW)
    sac_nb.add(child=cat_frame, text="合并列", sticky=NW)
    dfi_columns = list(i_m_table_dis.model.df)

    def split_column():
        global dfi
        try:
            if cmb_split_column.get() != "":
                column_type = i_m_table_dis.model.df[cmb_split_column.get()].dtype
                if np.issubdtype(column_type, object):
                    if e_split_separator.get() != "":
                        dfi[[e_split_new1.get(), e_split_new2.get()]] = dfi[cmb_split_column.get()].str.split(e_split_separator.get(), expand=True)
                        if not split_cb_var.get():
                            dfi = dfi.drop(cmb_split_column.get(), axis=1)
                        tk.messagebox.showinfo("Info", message='拆分成功！')
                        i_m_table_dis.model.df = dfi
                        i_update_info()
                    elif e_split_separator.get() == "":
                        tk.messagebox.showerror("Error", message='请输入分隔符！')
                else:
                    mb_toobject = tk.messagebox.askyesno("Prompt", message='该列数值类型不是字符串，无法拆分！是否将其转换为字符串继续拆分？')
                    if mb_toobject:
                        dfi[cmb_split_column.get()] = dfi[cmb_split_column.get()].astype(str)
                        if e_split_separator.get() != "":
                            dfi[[e_split_new1.get(), e_split_new2.get()]] = dfi[cmb_split_column.get()].str.split(
                                e_split_separator.get(), expand=True)
                            if not split_cb_var.get():
                                dfi = dfi.drop(cmb_split_column.get(), axis=1)
                            tk.messagebox.showinfo("Info", message='拆分成功！')
                            i_m_table_dis.model.df = dfi
                            i_update_info()
                        elif e_split_separator.get() == "":
                            tk.messagebox.showerror("Error", message='请输入分隔符！')
            else:
                tk.messagebox.showerror("Error", "请选择被拆分列！")
        except Exception as e:
            tk.messagebox.showerror("Error", f"拆分出错: {str(e)}")

    def explode_column():
        global dfi
        try:
            if cmb_explode_column.get() != "":
                column_type = i_m_table_dis.model.df[cmb_explode_column.get()].dtype
                if isinstance(column_type, list):
                    dfi = dfi.explode(cmb_explode_column.get())
                    tk.messagebox.showinfo("Info", message='拆分成功！')
                    i_m_table_dis.model.df = dfi
                    i_update_info()
                else:
                    mb_tolist = tk.messagebox.askyesno("Prompt", message='该列数值类型不是列表，无法拆分！是否将其转换为列表继续拆分？')
                    if mb_tolist:
                        dfi[cmb_explode_column.get()] = dfi[cmb_explode_column.get()].apply(lambda x: eval(x))
                        dfi = dfi.explode(cmb_explode_column.get())
                        tk.messagebox.showinfo("Info", message='拆分成功！')
                        i_m_table_dis.model.df = dfi
                        i_update_info()
            else:
                tk.messagebox.showerror("Error", "请选择被拆分列！")
        except Exception as e:
            tk.messagebox.showerror("Error", f"拆分出错: {str(e)}")

    def cat_column():
        global dfi
        try:
            if cmb_cat_column1.get() != "" and cmb_cat_column2.get() != "" and e_cat_newcolumn.get() != "":
                column_type1 = i_m_table_dis.model.df[cmb_cat_column1.get()].dtype
                column_type2 = i_m_table_dis.model.df[cmb_cat_column2.get()].dtype
                if np.issubdtype(column_type1, object) and np.issubdtype(column_type2, object):
                    if e_cat_separator.get() != "":
                        dfi[e_cat_newcolumn.get()] = dfi[cmb_cat_column1.get()].str.cat(dfi[cmb_cat_column2.get()], sep=e_cat_separator.get())
                    else:
                        dfi[e_cat_newcolumn.get()] = dfi[cmb_cat_column1.get()].str.cat(dfi[cmb_cat_column2.get()])
                    if not cat_cb_var.get():
                        dfi = dfi.drop([cmb_cat_column1.get(), cmb_cat_column2.get()], axis=1)
                    tk.messagebox.showinfo("Info", message='合并成功！')
                    i_m_table_dis.model.df = dfi
                    i_update_info()
                else:
                    mb_cat_toobject = tk.messagebox.askyesno("Prompt", message='合并列存在非字符串数值类型，无法合并！是否将其转换为字符串继续合并？')
                    if mb_cat_toobject:
                        dfi[cmb_cat_column1.get()] = dfi[cmb_cat_column1.get()].astype(str)
                        dfi[cmb_cat_column2.get()] = dfi[cmb_cat_column2.get()].astype(str)
                        if e_cat_separator.get() != "":
                            dfi[e_cat_newcolumn.get()] = dfi[cmb_cat_column1.get()].str.cat(dfi[cmb_cat_column2.get()], sep=e_cat_separator.get())
                        else:
                            dfi[e_cat_newcolumn.get()] = dfi[cmb_cat_column1.get()].str.cat(dfi[cmb_cat_column2.get()])
                        if not cat_cb_var.get():
                            dfi = dfi.drop([cmb_cat_column1.get(), cmb_cat_column2.get()], axis=1)
                        tk.messagebox.showinfo("Info", message='合并成功！')
                        i_m_table_dis.model.df = dfi
                        i_update_info()
            elif cmb_cat_column1.get() == "" or cmb_cat_column2.get() == "":
                tk.messagebox.showerror("Error", "请选择要合并的列！")
            elif e_cat_newcolumn.get() == "":
                tk.messagebox.showerror("Error", "请输入合并后的列名！")
        except Exception as e:
            tk.messagebox.showerror("Error", f"合并出错: {str(e)}")

    #split frame
    ttk.Label(split_frame, text="请选择列：", font=("微软雅黑", 10)).grid(row=0, column=0, padx=(25, 1), pady=2)
    cmb_split_column = ttk.Combobox(split_frame, font=("微软雅黑", 8), width=12, values=dfi_columns, state="readonly")
    cmb_split_column.grid(row=0, column=1, pady=2)
    ttk.Label(split_frame, text="请输入分隔符：", font=("微软雅黑", 10)).grid(row=1, column=0, padx=(25, 1), pady=2)
    e_split_separator = ttk.Entry(split_frame, font=("微软雅黑", 8), width=14)
    e_split_separator.grid(row=1, column=1, pady=2)
    ttk.Label(split_frame, text="新列名1：", font=("微软雅黑", 10)).grid(row=2, column=0, padx=(25, 1), pady=2)
    e_split_new1 = ttk.Entry(split_frame, font=("微软雅黑", 8), width=14)
    e_split_new1.grid(row=2, column=1, pady=2)
    ttk.Label(split_frame, text="新列名2：", font=("微软雅黑", 10)).grid(row=3, column=0, padx=(25, 1), pady=2)
    e_split_new2 = ttk.Entry(split_frame, font=("微软雅黑", 8), width=14)
    e_split_new2.grid(row=3, column=1, pady=2)
    split_check_b = ttk.Checkbutton(split_frame, text="保留被拆分列", variable=split_cb_var)
    split_check_b.grid(row=4, column=0, pady=3, columnspan=2)
    ttk.Button(split_frame, text="确定", style="outline", command=split_column).grid(row=5, column=0, pady=2) # command
    ttk.Button(split_frame, text="取消", style="outline", command=sac_window.destroy).grid(row=5, column=1, pady=2)

    #explode frame
    ttk.Label(explode_frame, text="请选择列：", font=("微软雅黑", 10)).grid(row=0, column=0, padx=(45, 1), pady=2)
    cmb_explode_column = ttk.Combobox(explode_frame, font=("微软雅黑", 8), width=12, values=dfi_columns, state="readonly")
    cmb_explode_column.grid(row=0, column=1, pady=2)
    ttk.Button(explode_frame, text="确定", style="outline", command=explode_column).grid(row=1, column=0, pady=10, padx=(50, 1)) # command
    ttk.Button(explode_frame, text="取消", style="outline", command=sac_window.destroy).grid(row=1, column=1, pady=10)

    #cat frame
    ttk.Label(cat_frame, text="请选择列1：", font=("微软雅黑", 10)).grid(row=0, column=0, padx=(25, 1), pady=2)
    cmb_cat_column1 = ttk.Combobox(cat_frame, font=("微软雅黑", 8), width=12, values=dfi_columns, state="readonly")
    cmb_cat_column1.grid(row=0, column=1, pady=2)
    ttk.Label(cat_frame, text="请选择列2：", font=("微软雅黑", 10)).grid(row=1, column=0, padx=(25, 1), pady=2)
    cmb_cat_column2 = ttk.Combobox(cat_frame, font=("微软雅黑", 8), width=12, values=dfi_columns, state="readonly")
    cmb_cat_column2.grid(row=1, column=1, pady=2)
    ttk.Label(cat_frame, text="请输入分隔符：", font=("微软雅黑", 10)).grid(row=2, column=0, padx=(25, 1), pady=2)
    e_cat_separator = ttk.Entry(cat_frame, font=("微软雅黑", 8), width=14)
    e_cat_separator.grid(row=2, column=1, pady=2)
    ttk.Label(cat_frame, text="请输入新列名：", font=("微软雅黑", 10)).grid(row=3, column=0, padx=(25, 1), pady=2)
    e_cat_newcolumn = ttk.Entry(cat_frame, font=("微软雅黑", 8), width=14)
    e_cat_newcolumn.grid(row=3, column=1, pady=2)
