def cut_bins():
    cut_bins_window = ttk.Toplevel()
    cut_bins_window.title("Cut bins")
    cut_bins_window.geometry("310x240")
    cut_bins_window.grab_set()
    cut_bins_window.place_window_center()
    dfi_columns = list(i_m_table_dis.model.df)

    def get_left_point():
        global bins_left_point
        column_min = float(i_m_table_dis.model.df[cmb_cut_bins_column.get()].min())
        if cmb_cut_bins_left.get() == '最小值':
            bins_left_point = column_min
        elif cmb_cut_bins_left.get() == '最小值向下取整':
            min_num = column_min
            bins_left_point = math.floor(min_num)
        elif cmb_cut_bins_left.get() == '最小值向下取10的倍数':
            min_num = column_min
            bins_left_point = math.floor(min_num / 10) * 10
        elif cmb_cut_bins_left.get() == '最小值向下取5的倍数':
            min_num = column_min
            round_tenth = math.floor(min_num / 10) * 10
            if min_num - round_tenth > 5 :
                bins_left_point = round_tenth + 5
            else:
                bins_left_point = round_tenth
        elif cmb_cut_bins_left.get() == '最小值向下取0.1的倍数':
            min_num = column_min
            bins_left_point = math.floor(min_num * 10) / 10
        return bins_left_point

    def cut_bins_2():
        global dfi
        try:
            if cmb_cut_bins_column.get() != "":
                column_type = i_m_table_dis.model.df[cmb_cut_bins_column.get()].dtype
                if np.issubdtype(column_type, float) or np.issubdtype(column_type, int):
                    if e_cut_bins_step.get() != "" and e_cut_bins_new_column.get() != "" and cmb_cut_bins_left.get() != "":
                        left_point = get_left_point()
                        right_point = i_m_table_dis.model.df[cmb_cut_bins_column.get()].max()
                        step = float(e_cut_bins_step.get())
                        bins = []
                        for element in np.arange(left_point, right_point + step, step):
                            bins.append(element)
                        dfi[e_cut_bins_new_column.get()] = pd.cut(dfi[cmb_cut_bins_column.get()], bins)
                        if not cut_bins_cb_var.get():
                            dfi = dfi.drop([cmb_cut_bins_column.get()], axis=1)
                        tk.messagebox.showinfo("Info", message='分箱成功！')
                        dfi[e_cut_bins_new_column.get()] = dfi[e_cut_bins_new_column.get()].astype(object)
                        i_m_table_dis.model.df = dfi
                        i_update_info()
                    elif e_cut_bins_step.get() == "":
                        tk.messagebox.showerror("Error", "请输入步长！")
                    elif cmb_cut_bins_left.get() == "":
                        tk.messagebox.showerror("Error", "请选择左端点！")
                    elif e_cut_bins_new_column.get() == "":
                        tk.messagebox.showerror("Error", "请输入新列名！")
                else:
                    mb_cut_bins_tofloat = tk.messagebox.askyesno("Prompt", message='该列数值类型为非数值，无法分箱！是否将其转换为数值并继续分箱？')
                    if mb_cut_bins_tofloat:
                        dfi[cmb_cut_bins_column.get()] = dfi[cmb_cut_bins_column.get()].astype(float)
                        if e_cut_bins_step.get() != "" and e_cut_bins_new_column.get() != "" and cmb_cut_bins_left.get() != "":
                            left_point = get_left_point()
                            right_point = i_m_table_dis[cmb_cut_bins_column.get()].max()
                            step = float(e_cut_bins_step.get())
                            bins = []
                            for element in np.arange(left_point, right_point + step, step):
                                bins.append(element)
                            dfi[e_cut_bins_new_column.get()] = pd.cut(dfi[cmb_cut_bins_column.get()], bins)
                            if not cut_bins_cb_var.get():
                                dfi = dfi.drop([cmb_cut_bins_column.get()], axis=1)
                            tk.messagebox.showinfo("Info", message='分箱成功！')
                            dfi[e_cut_bins_new_column.get()] = dfi[e_cut_bins_new_column.get()].astype(object)
                            i_m_table_dis.model.df = dfi
                            i_update_info()
                        elif e_cut_bins_step.get() == "":
                            tk.messagebox.showerror("Error", "请输入步长！")
                        elif cmb_cut_bins_left.get() == "":
                            tk.messagebox.showerror("Error", "请选择左端点！")
                        elif e_cut_bins_new_column.get() == "":
                            tk.messagebox.showerror("Error", "请输入新列名！")
            else:
                tk.messagebox.showerror("Error", "请输入分箱列名！")
        except Exception as e:
            tk.messagebox.showerror("Error", f"分箱出错: {str(e)}")

    ttk.Label(cut_bins_window, text="请选择列：", font=("微软雅黑", 10)).grid(row=0, column=0, padx=(25, 1), pady=2)
    cmb_cut_bins_column = ttk.Combobox(cut_bins_window, font=("微软雅黑", 8), width=14, values=dfi_columns, state="readonly")
    cmb_cut_bins_column.grid(row=0, column=1, pady=2)
    ttk.Label(cut_bins_window, text="请选择左端点：", font=("微软雅黑", 10)).grid(row=1, column=0, padx=(25, 1), pady=2)
    cmb_cut_bins_left = ttk.Combobox(cut_bins_window, font=("微软雅黑", 8), width=14, values=('最小值', '最小值向下取整', '最小值向下取10的倍数', '最小值向下取5的倍数', '最小值向下取0.1的倍数'), state="readonly")
    cmb_cut_bins_left.grid(row=1, column=1, pady=2)
    ttk.Label(cut_bins_window, text="请输入步长：", font=("微软雅黑", 10)).grid(row=2, column=0, padx=(25, 1), pady=2)
    e_cut_bins_step = ttk.Entry(cut_bins_window, font=("微软雅黑", 8), width=16)
    e_cut_bins_step.grid(row=2, column=1, pady=2)
    ttk.Label(cut_bins_window, text="请输入新列名：", font=("微软雅黑", 10)).grid(row=3, column=0, padx=(25, 1), pady=2)
    e_cut_bins_new_column = ttk.Entry(cut_bins_window, font=("微软雅黑", 8), width=16)
    e_cut_bins_new_column.grid(row=3, column=1, pady=2)
    cut_bins_check_b = ttk.Checkbutton(cut_bins_window, text="保留分箱前的列", variable=cut_bins_cb_var)
    cut_bins_check_b.grid(row=4, column=0, pady=3, columnspan=2)
    ttk.Button(cut_bins_window, text="确定", style="outline", command=cut_bins_2).grid(row=5, column=0, pady=3, padx=20)  # command
