def i_groupby():
    id_list = []
    v_list = []
    try:
        if i_groupby_lb_index.curselection() != "" and i_groupby_lb_value.curselection() != "" and i_gb_g_cmb4.get() != "":
            for index in i_groupby_lb_index.curselection():
                id_list.append(i_groupby_lb_index.get(index))
            for value in i_groupby_lb_value.curselection():
                v_list.append(i_groupby_lb_value.get(value))
            if i_gb_g_cmb4.get() == "求平均值":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].mean().reset_index()
            elif i_gb_g_cmb4.get() == "求中位数":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].median().reset_index()
            elif i_gb_g_cmb4.get() == "求和":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].sum().reset_index()
            elif i_gb_g_cmb4.get() == "求积":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].prod().reset_index()
            elif i_gb_g_cmb4.get() == "求元素个数":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].count().reset_index()
            elif i_gb_g_cmb4.get() == "求最大值":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].max().reset_index()
            elif i_gb_g_cmb4.get() == "求最小值":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].min().reset_index()
            elif i_gb_g_cmb4.get() == "求方差":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].var().reset_index()
            elif i_gb_g_cmb4.get() == "求标准差":
                i_m_table_dis.model.df = dfi.groupby(id_list)[v_list].std().reset_index()
            i_update_info()
            tk.messagebox.showinfo("Info", message='分组聚合成功！')
        elif i_groupby_lb_index.curselection() == "":
            tk.messagebox.showerror("Error", "请选择分组列！")
        elif i_groupby_lb_value.curselection() == "":
            tk.messagebox.showerror("Error", "请选择数值列！")
        elif i_gb_g_cmb4.get() == "":
            tk.messagebox.showerror("Error", "请选择聚合操作！")
    except Exception as e:
        tk.messagebox.showerror("Error", f"分组聚合出错: {str(e)}")

def i_pivot():
    global dfi
    id_list = []
    col_list = []
    v_list = []
    try:
        if i_pivot_lb_index.curselection() != "":
            for index in i_pivot_lb_index.curselection():
                id_list.append(i_pivot_lb_index.get(index))
        if i_pivot_lb_value.curselection() != "":
            for value in i_pivot_lb_value.curselection():
                v_list.append(i_pivot_lb_value.get(value))
        if i_pivot_lb_column.curselection() != "":
            for column in i_pivot_lb_column.curselection():
                col_list.append(i_pivot_lb_column.get(column))

        if i_pivot_aggfunc_cmb.get() == "求平均值":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.mean, margins=True).reset_index()
        elif i_pivot_aggfunc_cmb.get() == "求中位数":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.median, margins=True).reset_index()
        elif i_pivot_aggfunc_cmb.get() == "求和":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.sum, margins=True).reset_index()
        elif i_pivot_aggfunc_cmb.get() == "求积":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.prod, margins=True).reset_index()
        elif i_pivot_aggfunc_cmb.get() == "求最大值":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.max, margins=True).reset_index()
        elif i_pivot_aggfunc_cmb.get() == "求最小值":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.min, margins=True).reset_index()
        elif i_pivot_aggfunc_cmb.get() == "求方差":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.var, margins=True).reset_index()
        elif i_pivot_aggfunc_cmb.get() == "求标准差":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.std, margins=True).reset_index()
        elif i_pivot_aggfunc_cmb.get() == "求元素个数":
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, aggfunc=np.count_nonzero, margins=True).reset_index()
        else:
            dfi = pd.pivot_table(dfi, index=id_list, columns=col_list, values=v_list, margins=True).reset_index()

        i_m_table_dis.model.df = dfi
        i_update_info()
        tk.messagebox.showinfo("Info", message='透视表生成成功！')
    except Exception as e:
        tk.messagebox.showerror("Error", f"透视表生成出错: {str(e)}")

