def v_draw_plot():

    def select_estimator():
        global estimator
        if v_bar_plot_estimate_cmb.get() == '平均值':
            estimator = np.mean
        elif v_bar_plot_estimate_cmb.get() == '中位数':
            estimator = np.median
        elif v_bar_plot_estimate_cmb.get() == '和':
            estimator = np.sum
        elif v_bar_plot_estimate_cmb.get() == '积':
            estimator = np.prod
        elif v_bar_plot_estimate_cmb.get() == '最大值':
            estimator = np.max
        elif v_bar_plot_estimate_cmb.get() == '最小值':
            estimator = np.min
        elif v_bar_plot_estimate_cmb.get() == '方差':
            estimator = np.var
        elif v_bar_plot_estimate_cmb.get() == '标准差':
            estimator = np.std
        return estimator

    def select_ci():
        global ci
        if v_bar_plot_ci_cb_var.get() == False:
            ci = False
        else:
            ci = 95
        return ci

    def select_orient():
        global orient
        if v_bar_plot_orient_cmb.get() == '纵向':
            orient = "v"
        else:
            orient = "h"
        return orient

    def lp_select_color():
        color = color_dic[v_line_plot_color_label_cmb.get()]
        return str(color)

    def lp_select_marker():
        marker = marker_dic[v_line_plot_marker_label_cmb.get()]
        return str(marker)

    def lp_select_shape():
        shape = shape_dic[v_line_plot_shape_label_cmb.get()]
        return str(shape)

    def reg_line_color():
        l_color = color_dic[reg_line_color_cmb.get()]
        return str(l_color)

    def reg_point_color():
        p_color = color_dic[reg_point_color_cmb.get()]
        return str(p_color)

    def reg_select_ci():
        global reg_ci
        if not reg_ci_cb_var.get():
            reg_ci = None
        else:
            reg_ci = int(reg_ci_cmb.get())
        return reg_ci

    def reg_select_order():
        global reg_order
        if not reg_order_cb_var.get():
            reg_order = 1
        else:
            reg_order = int(reg_order_spinbox.get())
        return reg_order

    try:
        ax.clear()
        sns.set_palette(v_palette_cmb.get())
        v_b_save_path.config(state='normal')
        if graph_grid_cb_var.get():
            ax.grid(True)
        if not graph_xnumber_cb_var.get():
            ax.set_xticks([])
        if not graph_ynumber_cb_var.get():
            ax.set_yticks([])
        if graph_xnumber_rotation_cb_var.get():
            ax.tick_params(axis='x', labelrotation=45)
        else:
            ax.tick_params(axis='x', labelrotation=0)
        if graph_ynumber_rotation_cb_var.get():
            ax.tick_params(axis='y', labelrotation=45)
        else:
            ax.tick_params(axis='y', labelrotation=0)
        if v_title_e.get() != '':
            ax.set_title(v_title_e.get())
        if v_x_label_cmb.get() != '':
            ax.set_xlabel(v_x_label_cmb.get())
        if v_y_label_cmb.get() != '':
            ax.set_ylabel(v_y_label_cmb.get())

        if v_x_cmb.get() != '':
            if v_category_cmb.get() == '直方图':
                if v_hue_cmb.get() == "":
                    sns.histplot(dfv[v_x_cmb.get()], kde=v_bar_plot_ci_cb_var.get(),ax=ax)
                else:
                    sns.histplot(x=dfv[v_x_cmb.get()], hue=dfv[v_hue_cmb.get()], kde=v_bar_plot_ci_cb_var.get(),ax=ax)
            elif v_category_cmb.get() == '密度图':
                if v_y_cmb.get() == '':
                    sns.kdeplot(dfv[v_x_cmb.get()],ax=ax)
                else:
                    sns.kdeplot(x=dfv[v_x_cmb.get()], y=dfv[v_y_cmb.get()],ax=ax)
            elif v_category_cmb.get() == '箱型图':
                if v_y_cmb.get() == '':
                    sns.boxplot(dfv[v_x_cmb.get()],ax=ax)
                else:
                    sns.boxplot(x=dfv[v_x_cmb.get()], y=dfv[v_y_cmb.get()],ax=ax)
            elif v_category_cmb.get() == '小提琴图':
                if v_y_cmb.get() == '':
                    sns.violinplot(dfv[v_x_cmb.get()],ax=ax)
                else:
                    sns.violinplot(x=dfv[v_x_cmb.get()], y=dfv[v_y_cmb.get()],ax=ax)
            elif v_category_cmb.get() == '饼图':
                if v_pie_plot_label_cmb.get() == '':
                    plt.pie(dfv[v_x_cmb.get()], autopct='%1.{}f%%'.format(v_pie_plot_autopct_spinbox.get()))
                else:
                    plt.pie(dfv[v_x_cmb.get()], labels=dfv[v_pie_plot_label_cmb.get()]
                            , autopct='%1.{}f%%'.format(v_pie_plot_autopct_spinbox.get()))
                    plt.legend(bbox_to_anchor=(1, 1))
                plt.show()
            elif v_category_cmb.get() == '饼图（计数占比）':
                x_count = dfv[v_x_cmb.get()].value_counts()
                plt.pie(x_count, labels=x_count.index
                            , autopct='%1.{}f%%'.format(v_pie_plot_autopct_spinbox.get()))
                plt.legend(bbox_to_anchor=(1, 1))
                plt.show()
            elif v_category_cmb.get() == '计数图':
                sns.countplot(dfv[v_x_cmb.get()], ax=ax)
            elif v_category_cmb.get() == '条形图':
                estimator = select_estimator()
                ci = select_ci()
                orient = select_orient()
                if v_y_cmb.get() != '' and v_hue_cmb.get() != '':
                    sns.barplot(dfv, x=v_x_cmb.get(), y=v_y_cmb.get(), hue=v_hue_cmb.get(), ax=ax, estimator=estimator
                                , errorbar=('ci', ci), width=float(v_bar_plot_binwidth_spinbox.get()), orient=orient)
                elif v_y_cmb.get() != '' and v_hue_cmb.get() == '':
                    sns.barplot(dfv, x=v_x_cmb.get(), y=v_y_cmb.get(), ax=ax, estimator=estimator
                                , errorbar=('ci', ci), width=float(v_bar_plot_binwidth_spinbox.get()), orient=orient)
                elif v_y_cmb.get() == '':
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '折线图':
                color = lp_select_color()
                marker = lp_select_marker()
                shape = lp_select_shape()
                if v_y_cmb.get() != '':
                    ax.plot(dfv[v_x_cmb.get()], dfv[v_y_cmb.get()], linestyle=shape, color=color, marker=marker, label='L')
                elif v_y_cmb.get() == '':
                    ax.plot(dfv[v_x_cmb.get()], linestyle=shape, color=color, marker=marker, label='L')
                v_add_line_b.config(state='normal')
            elif v_category_cmb.get() == '折线图（分类变量）':
                if v_y_cmb.get() != '' and v_hue_cmb.get() != '':
                    sns.lineplot(data=dfv, x=v_x_cmb.get(), y=v_y_cmb.get(), hue=v_hue_cmb.get(), ax=ax)
                elif v_y_cmb.get() != '' and v_hue_cmb.get() == '':
                    sns.lineplot(data=dfv, x=v_x_cmb.get(), y=v_y_cmb.get(), ax=ax)
                elif v_y_cmb.get() == '':
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '散点图（气泡图）':
                if v_y_cmb.get() != '':
                    if v_hue_cmb.get() != '' and v_size_cmb.get() != '':
                        sns.scatterplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), hue =v_hue_cmb.get(), size = v_size_cmb.get(), ax=ax)
                    elif v_hue_cmb.get() != '' and v_size_cmb.get() == '':
                        sns.scatterplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), hue =v_hue_cmb.get(), ax=ax)
                    elif v_hue_cmb.get() == '' and v_size_cmb.get() != '':
                        sns.scatterplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), size = v_size_cmb.get(), ax=ax)
                    elif v_hue_cmb.get() == '' and v_size_cmb.get() == '':
                        sns.scatterplot(data=dfv, x=v_x_cmb.get(), y=v_y_cmb.get(), ax=ax)
                else:
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '一元线性回归':
                if v_y_cmb.get() != '':
                    l_color = reg_line_color()
                    p_color = reg_point_color()
                    reg_ci = reg_select_ci()
                    reg_order = reg_select_order()
                    sns.regplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), ax=ax, line_kws={'color': l_color}, scatter_kws={'color': p_color}
                                , ci=reg_ci, order=reg_order)
                else:
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '一元线性回归（逻辑回归）':
                if v_y_cmb.get() != '':
                    l_color = reg_line_color()
                    p_color = reg_point_color()
                    reg_ci = reg_select_ci()
                    reg_order = reg_select_order()
                    sns.regplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), ax=ax, line_kws={'color': l_color}, scatter_kws={'color': p_color}
                                , ci=reg_ci, order=reg_order, logistic=True)
                else:
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '一元线性回归（稳健回归）':
                if v_y_cmb.get() != '':
                    l_color = reg_line_color()
                    p_color = reg_point_color()
                    reg_ci = reg_select_ci()
                    reg_order = reg_select_order()
                    sns.regplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), ax=ax, line_kws={'color': l_color}, scatter_kws={'color': p_color}
                                , ci=reg_ci, order=reg_order, robust=True)
                else:
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '一元线性回归（局部加权）':
                if v_y_cmb.get() != '':
                    l_color = reg_line_color()
                    p_color = reg_point_color()
                    reg_ci = reg_select_ci()
                    reg_order = reg_select_order()
                    sns.regplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), ax=ax, line_kws={'color': l_color}, scatter_kws={'color': p_color}
                                , ci=reg_ci, order=reg_order, lowess=True)
                else:
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '一元线性回归（对数回归）':
                if v_y_cmb.get() != '':
                    l_color = reg_line_color()
                    p_color = reg_point_color()
                    reg_ci = reg_select_ci()
                    reg_order = reg_select_order()
                    sns.regplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), ax=ax, line_kws={'color': l_color}, scatter_kws={'color': p_color}
                                , ci=reg_ci, order=reg_order, logx=True)
                else:
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '一元线性回归（分类变量）':
                if v_y_cmb.get() != '' and v_hue_cmb.get() != '':
                    l_color = reg_line_color()
                    p_color = reg_point_color()
                    reg_ci = reg_select_ci()
                    reg_order = reg_select_order()
                    sns.lmplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), line_kws={'color': l_color}, scatter_kws={'color': p_color}
                                , ci=reg_ci, order=reg_order)
                    plt.show()
                elif v_y_cmb.get() == '':
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
                elif v_hue_cmb.get() == '':
                    tk.messagebox.showerror("Error", "请选择种类数据！")
            elif v_category_cmb.get() == '双变量与边际单变量':
                if v_y_cmb.get() != '':
                    l_color = reg_line_color()
                    p_color = reg_point_color()
                    reg_ci = reg_select_ci()
                    reg_order = reg_select_order()
                    if v_hue_cmb.get() != '':
                        sns.jointplot(data=dfv, x=v_x_cmb.get(), y =v_y_cmb.get(), hue=v_hue_cmb.get(), line_kws={'color': l_color},
                                      scatter_kws={'color': p_color}, ci=reg_ci, order=reg_order, kind='reg')
                    else:
                        sns.jointplot(data=dfv, x=v_x_cmb.get(), y=v_y_cmb.get(), line_kws={'color': l_color},
                                      scatter_kws={'color': p_color}, ci=reg_ci, order=reg_order, kind='reg')
                    plt.show()
                else:
                    tk.messagebox.showerror("Error", "请选择y轴数据！")
            elif v_category_cmb.get() == '热力图':
                sns.heatmap(data=dfv, ax=ax)
                plt.show()
            elif v_category_cmb.get() == '配对图':
                if v_hue_cmb.get() != '':
                    sns.pairplot(data=dfv, hue=v_hue_cmb.get())
                else:
                    sns.pairplot(data=dfv)
                plt.show()
        else:
            if v_category_cmb.get() == '热力图':
                sns.heatmap(data=dfv)
                plt.show()
            elif v_category_cmb.get() == '配对图':
                if v_hue_cmb.get() != '':
                    sns.pairplot(data=dfv, hue=v_hue_cmb.get())
                else:
                    sns.pairplot(data=dfv)
                plt.show()
            else:
                tk.messagebox.showerror("Error", "请选择x轴数据！")
        canvas.draw()
    except Exception as e:
        tk.messagebox.showerror("Error", f"绘制出错: {str(e)}")

