def v_add_line():
    global dfv
    adl_window = ttk.Toplevel()
    adl_window.title("Add Line")
    adl_window.geometry("500x198")
    adl_window.grab_set()
    adl_window.place_window_center()
    dfv_columns = list(dfv)

    adl_listbox = tk.Listbox(adl_window, height=9, width=12)
    adl_listbox.grid(row=0, column=0, rowspan=5, padx=(5,0))
    adl_listbox_yscrollbar = ttk.Scrollbar(adl_window, command=adl_listbox.yview, style="round")
    adl_listbox_yscrollbar.grid(row=0, column=1, sticky=NS, rowspan=5)
    adl_listbox.config(yscrollcommand=adl_listbox_yscrollbar.set)

    def add_line_name():
        adl_listbox.delete(0, END)
        for line_name in adl_name_list:
            adl_listbox.insert(END,str(line_name))

    add_line_name()

    adl_edit_frame = ttk.Frame(adl_window)
    adl_edit_frame.grid(row=0, column=2, columnspan=6, sticky=EW)

    tk.Label(adl_edit_frame, text='线条名称:', font=("微软雅黑", 10)).pack(side='left')
    adl_name_e = ttk.Entry(adl_edit_frame, textvariable=adl_name_var, font=("微软雅黑", 8), width=10)
    adl_name_e.pack(side='left')
    adl_add_b = ttk.Button(adl_edit_frame, text='添加', cursor='hand2')
